1	/**
2	 * Worktree Manager — creates, bootstraps, and cleans up git worktrees.
3	 *
4	 * Responsibilities (plan-draft3 §Worktree Management, D40):
5	 *   - Create a git branch + worktree under <baseDir>/<slug>-<shortid>/
6	 *   - Run bootstrap.commands as a state-machine phase, raising
7	 *     bootstrap_ok / bootstrap_fail events (consumed by Pipeline Engine).
8	 *   - Invoke .yoke/teardown.sh (if present) before git worktree remove.
9	 *   - Ordered cleanup: kill tracked pids → teardown → git worktree remove
10	 *     --force → branch retention decision.
11	 *   - Refuse auto-cleanup if branch has unpushed commits without a PR.
12	 *
13	 * Non-responsibilities:
14	 *   - Does NOT apply state-machine transitions (Pipeline Engine's job).
15	 *   - Does NOT parse NDJSON (StreamJsonParser's job).
16	 *   - Does NOT manage long-running agent sessions (ProcessManager's job).
17	 *
18	 * Review criteria compliance:
19	 *   RC-1  runBootstrap() returns a BootstrapEvent for the Pipeline Engine
20	 *         to apply via transition(); this module never calls transition().
21	 *   RC-2  Branch retention decision uses 'git log --not --remotes',
22	 *         reading the git remote state — not just local refs.
23	 *   RC-3  'git worktree remove --force' is called only after runTeardown().
24	 *   RC-4  Worktree path validated: must be absolute and strictly under baseDir.
25	 */
26	
27	import { execFile } from 'node:child_process';
28	import { promisify } from 'node:util';
29	import fs from 'node:fs';
30	import path from 'node:path';
