98	}
99	
100	export interface CleanupOpts {
101	  workflowId: string;
102	  worktreePath: string;
103	  branchName: string;
104	  /** OS PIDs of child processes to kill before teardown. */
105	  trackedPids: number[];
106	  /**
107	   * Milliseconds to wait after SIGTERM before escalating to SIGKILL.
108	   * Defaults to 10 000 ms.
109	   */
110	  gracePeriodMs?: number;
111	}
112	
113	export interface CleanupResult {
114	  worktreeRemoved: boolean;
115	  /**
116	   * True when the worktree was NOT removed because the branch has unpushed
117	   * commits and no corresponding PR was found (AC-5).
118	   */
119	  branchRetained: boolean;
120	  refusedReason?: 'unpushed_commits_no_pr';
121	}
122	
123	/**
124	 * Testability seam for the GitHub PR existence check.
125	 * Production code uses the default implementation that runs 'gh pr list'.
126	 */
127	export type CheckPrFn = (branchName: string, repoRoot: string) => Promise<boolean>;
128	
129	// ---------------------------------------------------------------------------
130	// WorktreeManager
131	// ---------------------------------------------------------------------------
132	
133	export interface WorktreeManagerOpts {
134	  /** Absolute path to the git repository root. */
135	  repoRoot: string;
136	  /**
137	   * Optional override for the PR existence check.
138	   * Defaults to running 'gh pr list --head <branch> --json number'.
139	   * Pass a stub in tests to avoid requiring the gh CLI.
140	   */
141	  checkPr?: CheckPrFn;
142	}
143	
144	export class WorktreeManager {
145	  private readonly repoRoot: string;
146	  private readonly checkPrFn: CheckPrFn;
147	
148	  constructor(opts: WorktreeManagerOpts) {
149	    this.repoRoot = opts.repoRoot;
150	    this.checkPrFn = opts.checkPr ?? defaultCheckPr;
151	  }
152	
153	  // -------------------------------------------------------------------------
154	  // createWorktree — AC-1, RC-4
155	  // -------------------------------------------------------------------------
156	
157	  /**
158	   * Creates a git branch + worktree under baseDir.
159	   *
160	   * Branch name:    yoke/<slug>-<shortid>
161	   * Worktree path:  <baseDir>/<slug>-<shortid>  (absolute, validated)
162	   *
163	   * After the worktree is created, writes branch_name and worktree_path to
164	   * the workflows row inside a single database transaction (AC-1).
165	   *
166	   * @throws {WorktreeError} kind='path_traversal' if computed path escapes baseDir.
167	   * @throws {WorktreeError} kind='git_error' if git worktree add fails.
168	   */
169	  async createWorktree(opts: CreateWorktreeOpts, db: DbPool): Promise<WorktreeInfo> {
170	    const { workflowId, workflowName, baseDir, branchPrefix = 'yoke/' } = opts;
171	
172	    const branchName = makeBranchName(workflowName, workflowId, branchPrefix);
173	    const dirName = makeWorktreeDirName(workflowName, workflowId);
174	    // path.resolve ensures the result is absolute even if baseDir is relative.
175	    const worktreePath = path.resolve(baseDir, dirName);
176	
177	    // RC-4: validate path is absolute and strictly under baseDir.
178	    this._validateWorktreePath(worktreePath, baseDir);
179	
180	    // Ensure the base directory exists before git worktree add creates the subdir.
181	    fs.mkdirSync(path.resolve(baseDir), { recursive: true });
182	
183	    // 'git worktree add -b <branch> <path>' creates the branch at HEAD and
184	    // checks it out in the new worktree directory in one atomic git operation.
185	    try {
186	      await execFileAsync('git', [
187	        '-C', this.repoRoot,
188	        'worktree', 'add',
189	        '-b', branchName,
190	        worktreePath,
191	      ]);
192	    } catch (err) {
193	      throw new WorktreeError(
194	        'git_error',
195	        `Failed to create worktree '${worktreePath}' on branch '${branchName}': ${(err as Error).message}`,
196	        err,
197	      );
198	    }
199	
200	    // Write branch_name and worktree_path inside a single transaction (AC-1).
201	    db.transaction((writer) => {
202	      writer
203	        .prepare(
204	          `UPDATE workflows
205	              SET branch_name   = ?,
206	                  worktree_path = ?,
207	                  updated_at    = ?
208	            WHERE id = ?`,
209	        )
210	        .run(branchName, worktreePath, new Date().toISOString(), workflowId);
211	    });
212	
213	    return { branchName, worktreePath };
214	  }
215	
216	  // -------------------------------------------------------------------------
217	  // runBootstrap — AC-2, AC-3, RC-1
218	  // -------------------------------------------------------------------------
219	
220	  /**
221	   * Runs bootstrap.commands in declared order as a state-machine phase (RC-1).
222	   *
223	   * Returns a BootstrapEvent for the Pipeline Engine to consume:
224	   *   bootstrap_ok   — all commands exited 0.
225	   *   bootstrap_fail — a command exited non-zero; subsequent commands are skipped.
226	   *
227	   * On bootstrap_fail: inserts a pending_attention row (kind='bootstrap_failed')
228	   * so the dashboard banner fires (AC-2).
229	   *
230	   * The returned event type is what the Pipeline Engine passes to transition():
231	   *   transition('bootstrapping', event.type)
232	   * This module never calls transition() itself (RC-1).
233	   *
234	   * AC-3 (bootstrap_failed never auto-cleans) is enforced by the state machine:
235	   * the Pipeline Engine only calls cleanup() on transitions that lead to
236	   * cleanup side effects; bootstrap_failed has no such transition.
237	   */
238	  async runBootstrap(opts: RunBootstrapOpts, db: DbPool): Promise<BootstrapEvent> {
239	    const { workflowId, worktreePath, commands } = opts;
240	
241	    for (const cmd of commands) {
242	      const result = await this._runShellCommand(cmd, worktreePath);
243	
244	      if (result.exitCode !== 0) {
245	        const event: BootstrapEvent = {
246	          type: 'bootstrap_fail',
247	          failedCommand: cmd,
248	          exitCode: result.exitCode ?? 1,
249	          stderr: result.stderr,
250	        };
251	
252	        // Insert pending_attention so the dashboard banner fires (AC-2).
253	        db.transaction((writer) => {
254	          writer
255	            .prepare(
256	              `INSERT INTO pending_attention (workflow_id, kind, payload, created_at)
257	               VALUES (?, 'bootstrap_failed', ?, ?)`,
258	            )
259	            .run(
260	              workflowId,
261	              JSON.stringify({
262	                failedCommand: cmd,
263	                exitCode: result.exitCode,
264	                stderr: result.stderr,
265	              }),
266	              new Date().toISOString(),
267	            );
268	        });
269	
270	        return event;
271	      }
272	    }
273	
274	    return { type: 'bootstrap_ok' };
275	  }
276	
277	  // -------------------------------------------------------------------------
278	  // runTeardown — AC-4
279	  // -------------------------------------------------------------------------
280	
281	  /**
282	   * Invokes .yoke/teardown.sh in the worktree directory, if it exists.
283	   *
284	   * Absence of the script is NOT an error (AC-4). A non-zero exit is
285	   * treated as non-fatal: a warning is logged and cleanup continues.
286	   * This mirrors the semantics described in plan-draft3 §Worktree Management:
287	   * teardown stops containers and closes sockets — failure should not prevent
288	   * the worktree from being removed.
289	   */
290	  async runTeardown(worktreePath: string): Promise<void> {
291	    const teardownScript = path.join(worktreePath, '.yoke', 'teardown.sh');
292	
293	    if (!fs.existsSync(teardownScript)) {
294	      return; // Absence is not an error (AC-4).
295	    }
296	
297	    try {
298	      await execFileAsync('sh', [teardownScript], { cwd: worktreePath });
299	    } catch {
300	      // Non-zero exit from teardown.sh is non-fatal — log a warning and
301	      // continue cleanup so the worktree is still removed.
302	      console.warn(
303	        `[worktree] .yoke/teardown.sh exited non-zero in '${worktreePath}'; continuing cleanup`,
304	      );
305	    }
306	  }
307	
308	  // -------------------------------------------------------------------------
309	  // cleanup — AC-4, AC-5, AC-6, RC-2, RC-3
310	  // -------------------------------------------------------------------------
311	
312	  /**
313	   * Performs ordered worktree cleanup:
314	   *
315	   *   Pre-check — refuse cleanup if branch has unpushed commits without a PR
316	   *               (AC-5). Logs a warning and returns without destructive action.
317	   *
318	   *   Step 1    — kill tracked pids (SIGTERM → gracePeriodMs → SIGKILL).
319	   *   Step 2    — run .yoke/teardown.sh if present (AC-4).
320	   *   Step 3    — git worktree remove --force (RC-3: only after teardown).
321	   *   Step 4    — branch retention decision (v1: keep branch by default).
322	   *
323	   * @throws {WorktreeError} kind='git_error' if git worktree remove fails.
324	   */
325	  async cleanup(opts: CleanupOpts): Promise<CleanupResult> {
326	    const { worktreePath, branchName, trackedPids, gracePeriodMs = 10_000 } = opts;
327	
328	    // Pre-check: branch retention guard (AC-5, RC-2).
329	    // _hasUnpushedCommits reads the git remote state (not just local refs).
330	    const hasUnpushed = await this._hasUnpushedCommits(branchName);
331	    if (hasUnpushed) {
332	      const prExists = await this.checkPrFn(branchName, this.repoRoot);
333	      if (!prExists) {
334	        console.warn(
335	          `[worktree] auto-cleanup refused for branch '${branchName}': ` +
336	            'branch has unpushed commits and no open PR was found. ' +
337	            "Push the branch or create a PR before cleanup, or use 'yoke cancel' to force.",
338	        );
339	        return { worktreeRemoved: false, branchRetained: true, refusedReason: 'unpushed_commits_no_pr' };
340	      }
341	    }
342	
343	    // Step 1: Kill tracked pids (SIGTERM → SIGKILL escalation).
344	    for (const pid of trackedPids) {
345	      await killProcessGroup(pid, gracePeriodMs);
346	    }
347	
348	    // Step 2: Teardown hook (AC-4); must complete before git worktree remove (RC-3).
349	    await this.runTeardown(worktreePath);
350	
351	    // Step 3: git worktree remove --force.
352	    // '--force' is used only here — AFTER teardown has run (RC-3).
353	    try {
354	      await execFileAsync('git', [
355	        '-C', this.repoRoot,
356	        'worktree', 'remove', '--force', worktreePath,
357	      ]);
358	    } catch (err) {
359	      throw new WorktreeError(
360	        'git_error',
361	        `Failed to remove worktree '${worktreePath}': ${(err as Error).message}`,
362	        err,
363	      );
364	    }
365	
366	    // Step 4: Branch retention decision.
367	    // v1: retain the branch after worktree removal. The branch is still
368	    // accessible via 'git checkout yoke/<name>-<shortid>' for inspection.
369	    // Branch deletion (e.g. after merge) is out of v1 scope per plan-draft3
370	    // §Worktree Management (D40 §Rules).
371	
372	    return { worktreeRemoved: true, branchRetained: false };
373	  }
374	
375	  // -------------------------------------------------------------------------
376	  // Private helpers
377	  // -------------------------------------------------------------------------
378	
379	  /**
380	   * Validates that worktreePath:
381	   *   1. Is an absolute path.
382	   *   2. Is strictly under baseDir (no '..' traversal escapes).
383	   *
384	   * RC-4: every worktree is confined to the user-configured baseDir.
385	   */
386	  private _validateWorktreePath(worktreePath: string, baseDir: string): void {
387	    if (!path.isAbsolute(worktreePath)) {
388	      throw new WorktreeError(
389	        'invalid_path',
390	        `Worktree path must be absolute; got: '${worktreePath}'`,
391	      );
392	    }
393	
394	    const canonicalBase = path.resolve(baseDir);
395	    const canonicalWorktree = path.resolve(worktreePath);
396	
397	    // The resolved path must START with baseDir + sep to prevent:
398	    //   - A path that equals baseDir itself (not a subdirectory).
399	    //   - A path that starts with baseDir but then has a different continuation
400	    //     after a symlink (not a concern here since we use resolve).
401	    if (!canonicalWorktree.startsWith(canonicalBase + path.sep)) {
402	      throw new WorktreeError(
403	        'path_traversal',
404	        `Worktree path '${worktreePath}' is not under base directory '${baseDir}'`,
405	      );
406	    }
407	  }
408	
409	  /**
410	   * Runs a single shell command string (from bootstrap.commands or teardown).
411	   *
412	   * Uses 'sh -c <cmd>' so commands like 'pnpm install' or 'docker compose up -d'
413	   * work without needing argv-splitting. The .yoke.yml is user-authored and
414	   * trusted per the architecture threat model.
415	   *
416	   * Captures stderr (capped at 4 KB). Returns exit code and stderr string.
417	   * Never throws — spawn failures are represented as { exitCode: 1 }.
418	   */
419	  private async _runShellCommand(
420	    cmd: string,
421	    cwd: string,
422	  ): Promise<{ exitCode: number | null; stderr: string }> {
423	    try {
424	      await execFileAsync('sh', ['-c', cmd], {
425	        cwd,
426	        env: { ...process.env },
427	        maxBuffer: 4 * 1024 * 1024, // 4 MB stdout/stderr buffer
428	      });
429	      return { exitCode: 0, stderr: '' };
430	    } catch (err: unknown) {
431	      // execFileAsync rejects with an error that carries .code (exit code)
432	      // and .stderr (captured stderr string) when the command exits non-zero.
433	      // When sh itself cannot be spawned, .code is a string like 'ENOENT'.
434	      const e = err as { code?: unknown; stderr?: unknown };
435	      const exitCode = typeof e.code === 'number' ? e.code : 1;
436	      const rawStderr = typeof e.stderr === 'string' ? e.stderr : '';
437	      return { exitCode, stderr: rawStderr.slice(0, 4096) };
438	    }
439	  }
440	
441	  /**
442	   * Checks whether the branch has commits not present on any remote tracking
443	   * branch (RC-2: reads git remote state, not just local refs).
444	   *
445	   * Uses 'git log <branch> --not --remotes --oneline':
446	   *   - Empty output → all commits are on a remote → false.
447	   *   - Non-empty output → unpushed commits exist → true.
448	   *
449	   * If no remote is configured, '--remotes' is empty so '--not --remotes'
450	   * filters nothing: all commits appear as "unpushed." This is the
451	   * conservative direction — refuse cleanup unless a PR exists.
452	   *
453	   * Returns false on git command failure (e.g. branch does not yet exist)
454	   * so cleanup of invalid/pre-push branches is not blocked.
455	   */
456	  private async _hasUnpushedCommits(branchName: string): Promise<boolean> {
457	    try {
458	      const { stdout } = await execFileAsync('git', [
459	        '-C', this.repoRoot,
460	        'log', branchName,
461	        '--not', '--remotes',
462	        '--oneline',
463	      ]);
464	      return stdout.trim().length > 0;
465	    } catch {
466	      // Branch may not exist yet or git is not available — treat as no
467	      // unpushed commits so cleanup of non-existent branches is not blocked.
468	      return false;
469	    }
470	  }
471	}
472	
473	// ---------------------------------------------------------------------------
474	// Default PR existence check (production implementation)
475	// ---------------------------------------------------------------------------
476	
477	/**
478	 * Checks whether a PR exists for the given branch using the 'gh' CLI.
479	 *
480	 * 'gh pr list --head <branch> --json number' returns a JSON array:
481	 *   Non-empty → PR exists → cleanup is allowed even with unpushed commits.
482	 *   Empty []  → no PR → refuse cleanup if unpushed commits are present.
483	 *
484	 * If 'gh' is not installed, not authenticated, or the remote is not GitHub,
485	 * returns false — the conservative direction (refuse cleanup).
486	 */
487	const defaultCheckPr: CheckPrFn = async (
488	  branchName: string,
489	  repoRoot: string,
490	): Promise<boolean> => {
491	  try {
492	    const { stdout } = await execFileAsync(
493	      'gh',
494	      ['pr', 'list', '--head', branchName, '--json', 'number'],
495	      { cwd: repoRoot },
496	    );
497	    const parsed = JSON.parse(stdout.trim());
498	    return Array.isArray(parsed) && parsed.length > 0;
499	  } catch {
500	    // gh not installed, not authenticated, or non-GitHub remote.
501	    // Safe direction: treat as no PR.
502	    return false;
503	  }
504	};
505	
506	// ---------------------------------------------------------------------------
507	// killProcessGroup — SIGTERM → SIGKILL escalation
508	// ---------------------------------------------------------------------------
509	
510	/**
511	 * Sends SIGTERM to the process group of `pid`, waits up to `gracePeriodMs`,
512	 * then sends SIGKILL if the process group is still alive.
513	 *
514	 * Used in cleanup step 1 to kill tracked child pids before teardown runs.
515	 *
516	 * SIGTERM is sent to -pid (the entire process group), matching the shutdown
517	 * contract in plan-draft3 §Process Management §Shutdown.
518	 */
519	async function killProcessGroup(pid: number, gracePeriodMs: number): Promise<void> {
520	  try {
521	    process.kill(-pid, 'SIGTERM');
522	  } catch {
523	    // ESRCH: process group already gone — not an error.
524	    return;
525	  }
526	
527	  return new Promise<void>((resolve) => {
528	    // Poll at 50 ms intervals to detect natural death.
529	    const poll = setInterval(() => {
530	      try {
531	        process.kill(pid, 0); // liveness probe
532	      } catch {
533	        // ESRCH: process died naturally before the grace period expired.
534	        clearInterval(poll);
535	        clearTimeout(timer);
536	        resolve();
537	      }
538	    }, 50);
539	
540	    // Escalate to SIGKILL after the grace period.
541	    const timer = setTimeout(() => {
542	      clearInterval(poll);
543	      try {
544	        process.kill(-pid, 'SIGKILL');
545	      } catch {
546	        // Process group gone between SIGTERM and SIGKILL — fine.
547	      }
548	      resolve();
549	    }, gracePeriodMs);
550	  });
551	}
